<?php
namespace Tests\Feature;
use App\Models\User; use App\Models\WatchlistItem; use Illuminate\Foundation\Testing\RefreshDatabase; use Illuminate\Support\Facades\Http; use Laravel\Sanctum\Sanctum; use Tests\TestCase;
class WatchlistTest extends TestCase { use RefreshDatabase; private function omdbPayload(): array { return ['Title'=>'Guardians of the Galaxy Vol. 2','Year'=>'2017','Rated'=>'PG-13','Released'=>'05 May 2017','Runtime'=>'136 min','Genre'=>'Action, Adventure, Comedy','Director'=>'James Gunn','Writer'=>'James Gunn','Actors'=>'Chris Pratt, Zoe Saldana','Plot'=>'The Guardians continue their adventures.','Language'=>'English','Country'=>'United States','Awards'=>'Nominated for 1 Oscar','Poster'=>'https://example.test/poster.jpg','imdbRating'=>'7.6','imdbVotes'=>'800,000','imdbID'=>'tt3896198','Type'=>'movie','Response'=>'True']; }
 public function test_authenticated_user_can_add_movie_from_omdb(): void { config(['services.omdb.key'=>'test-key','services.omdb.base_url'=>'https://www.omdbapi.com']); Http::fake(['www.omdbapi.com*'=>Http::response($this->omdbPayload())]); Sanctum::actingAs(User::factory()->create()); $this->postJson('/api/v1/watchlist',['identifier'=>'tt3896198','status'=>'watching','favorite'=>true])->assertCreated()->assertJsonPath('data.imdb_id','tt3896198')->assertJsonPath('data.status','watching'); $this->assertDatabaseHas('watchlist_items',['imdb_id'=>'tt3896198','title'=>'Guardians of the Galaxy Vol. 2','favorite'=>true]); }
 public function test_watchlist_is_scoped_to_authenticated_user(): void { $owner = User::factory()->create(); $other = User::factory()->create(); $item = WatchlistItem::factory()->for($owner)->create(['title'=>'Private Movie']); Sanctum::actingAs($other); $this->getJson('/api/v1/watchlist/'.$item->id)->assertNotFound(); }
 public function test_user_can_filter_paginate_and_update_items(): void { $user = User::factory()->create(); WatchlistItem::factory()->for($user)->create(['title'=>'Alien','status'=>'watched','favorite'=>true]); WatchlistItem::factory()->for($user)->create(['title'=>'Arrival','status'=>'to_watch','favorite'=>false]); Sanctum::actingAs($user); $this->getJson('/api/v1/watchlist?status=watched&favorite=1&per_page=5')->assertOk()->assertJsonPath('data.0.title','Alien')->assertJsonCount(1,'data'); $item = $user->watchlistItems()->where('title','Alien')->first(); $this->patchJson('/api/v1/watchlist/'.$item->id,['status'=>'watched','rating'=>9,'notes'=>'Great rewatch.'])->assertOk()->assertJsonPath('data.rating',9); }
 public function test_duplicate_movie_for_same_user_is_rejected(): void { config(['services.omdb.key'=>'test-key','services.omdb.base_url'=>'https://www.omdbapi.com']); Http::fake(['www.omdbapi.com*'=>Http::response($this->omdbPayload())]); $user = User::factory()->create(); WatchlistItem::factory()->for($user)->create(['imdb_id'=>'tt3896198']); Sanctum::actingAs($user); $this->postJson('/api/v1/watchlist',['identifier'=>'tt3896198'])->assertStatus(422); } }
